import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, addDoc, serverTimestamp } from 'firebase/firestore';

const Booking = () => {
  const { bikeId } = useParams();
  const [bike, setBike] = useState(null);
  const [loading, setLoading] = useState(true);
  const [quantity, setQuantity] = useState(1);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    fetchBike();
  }, [bikeId]);

  const fetchBike = async () => {
    try {
      const bikeRef = doc(db, 'bikes', bikeId);
      const bikeSnap = await getDoc(bikeRef);

      if (bikeSnap.exists()) {
        const bikeData = { id: bikeSnap.id, ...bikeSnap.data() };
        setBike(bikeData);
        setQuantity(1);
      } else {
        console.log("No such bike in Firestore!");
      }
    } catch (error) {
      console.error('Error fetching bike:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatPrice = (price) => new Intl.NumberFormat('en-IN').format(price);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData(e.target);
      const bookingData = {
        bikeId,
        bikeName: bike.name,
        quantity: 1,
        totalAmount: bike.price,
        location: formData.get('location'),
        customerName: formData.get('fullName'),
        email: formData.get('email'),
        phone: formData.get('phone'),
        notes: formData.get('notes'),
        status: 'confirmed',
        createdAt: serverTimestamp()
      };

      await addDoc(collection(db, 'bookings'), bookingData);
      setSubmitted(true);
    } catch (error) {
      console.error("Error submitting booking:", error);
      alert("Failed to submit booking. Please try again.");
    }
  };

  if (loading) {
    return <div className="loading"><div className="spinner"></div></div>;
  }

  if (!bike) {
    return (
      <div className="empty-state">
        <div className="empty-state-icon">🔍</div>
        <h3>Bike not found</h3>
        <p>The requested bike listing could not be found</p>
        <Link to="/inventory" className="btn btn-primary" style={{ marginTop: '1rem' }}>← Back to Inventory</Link>
      </div>
    );
  }

  if (submitted) {
    return (
      <div style={{ textAlign: 'center', padding: '4rem 2rem' }}>
        <div style={{ fontSize: '4rem', marginBottom: '1.5rem' }}>✅</div>
        <h2 style={{ fontSize: '1.75rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '0.75rem' }}>Booking Confirmed!</h2>
        <p style={{ color: 'var(--text-secondary)', marginBottom: '0.5rem', fontSize: '1rem' }}>
          Your ride with <strong>{bike.name}</strong> has been secured.
        </p>
        <p style={{ color: 'var(--text-muted)', marginBottom: '2rem', fontSize: '0.85rem' }}>
          Check your email for booking details and pickup instructions.
        </p>
        <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center' }}>
          <Link to="/inventory" className="btn btn-primary btn-lg">🏍️ Explore More</Link>
          <Link to="/orders" className="btn btn-outline btn-lg">📋 View My Bookings</Link>
        </div>
      </div>
    );
  }

  const totalAmount = bike.price;

  return (
    <div>
      <div className="page-header">
        <div className="page-header-row">
          <div>
            <h1>📅 Complete Your Booking</h1>
            <p>You're just one step away from your ride with {bike.name}</p>
          </div>
          <Link to="/inventory" className="btn btn-outline">← Back</Link>
        </div>
      </div>

      <div className="dashboard-grid dashboard-grid--2">
        {/* Bike Details */}
        <div className="card">
          <div className="card-header">
            <h3>🏍️ Ride Summary</h3>
            {bike.verified && <span className="badge badge--success">✓ Verified Bike</span>}
          </div>
          <div className="card-body">
            <div style={{ borderRadius: 'var(--radius)', overflow: 'hidden', marginBottom: '1.25rem', height: '220px', background: 'var(--bg-surface)' }}>
              {bike.image_url ? (
                <img src={bike.image_url} alt={bike.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
              ) : (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', fontSize: '3rem', opacity: 0.3 }}>🏍️</div>
              )}
            </div>

            <h2 style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '0.25rem' }}>{bike.name}</h2>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '1.25rem' }}>{bike.brand || bike.category} • {bike.engine_cc || '—'}cc</p>

            <div className="b2b-card-price-section" style={{ marginBottom: '1.5rem' }}>
              <span className="b2b-price-label">Daily Rental Rate</span>
              <span className="b2b-price-value">₹{formatPrice(bike.price)}</span>
            </div>

            <div className="b2b-card-specs-minimal">
              <div className="b2b-spec-item">
                <span className="b2b-spec-icon">⭐</span>
                <span>{bike.rating || '4.0'}</span>
              </div>
              <div className="b2b-spec-item">
                <span className="b2b-spec-icon">🚚</span>
                <span>{bike.delivery_days || 7} days delivery</span>
              </div>
            </div>

            <div style={{ marginTop: '1rem', padding: '1rem', background: 'var(--bg-surface)', borderRadius: 'var(--radius-sm)' }}>
              <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '0.25rem' }}>Category</div>
              <div style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-primary)' }}>{bike.category || 'Standard'}</div>
            </div>
          </div>
        </div>

        {/* Booking Form */}
        <div className="card">
          <div className="card-header">
            <h3>📋 Personal Details</h3>
          </div>
          <div className="card-body">
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label className="form-label">Full Name</label>
                <input className="form-input" name="fullName" type="text" placeholder="Enter your full name" required />
              </div>

              <div className="form-group">
                <label className="form-label">Pickup Location</label>
                <input className="form-input" name="location" type="text" placeholder="Your City" required />
              </div>

              <div className="form-group">
                <label className="form-label">Email Address</label>
                <input className="form-input" name="email" type="email" placeholder="name@example.com" required />
              </div>

              <div className="form-group">
                <label className="form-label">Phone Number</label>
                <input className="form-input" name="phone" type="tel" placeholder="+91 XXXXX XXXXX" required />
              </div>

              <div className="form-group">
                <label className="form-label">Special Requests (Optional)</label>
                <textarea className="form-textarea" name="notes" placeholder="Color preference, accessory requirements..."></textarea>
              </div>

              {/* Summary */}
              <div style={{ padding: '1.25rem', background: 'var(--bg-surface)', borderRadius: 'var(--radius-sm)', marginBottom: '1.25rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Rental Rate</span>
                  <span style={{ fontSize: '0.8rem', fontWeight: 600, color: 'var(--text-primary)' }}>₹{formatPrice(bike.price)}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Quantity</span>
                  <span style={{ fontSize: '0.8rem', fontWeight: 600, color: 'var(--text-primary)' }}>1 Bike</span>
                </div>
                <div style={{ height: '1px', background: 'var(--border)', margin: '0.75rem 0' }}></div>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span style={{ fontSize: '0.9rem', fontWeight: 700, color: 'var(--text-primary)' }}>Total Price</span>
                  <span style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-light)' }}>₹{formatPrice(totalAmount)}</span>
                </div>
              </div>

              <button type="submit" className="btn btn-primary btn-lg" style={{ width: '100%' }}>
                ⚡ Confirm Booking
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Booking;
